104→<script>
105→    // Admin menu visibility control based on user role
106→    function updateAdminVisibility() {
107→        const user = (window as any).currentUser;
108→        const hasAdmin = user?.roles?.includes('ADMIN') || false;
109→
110→        // Find the Admin menu item link
111→        const adminLink = document.querySelector('a[href="/admin"]');
112→        if (adminLink) {
113→            const adminListItem = adminLink.closest('li');
114→            if (adminListItem) {
115→                // Show or hide based on admin role
116→                adminListItem.style.display = hasAdmin ? 'block' : 'none';
117→            }
118→        }
119→    }
120→
121→    // Update visibility when user data is loaded
122→    window.addEventListener('userLoaded', updateAdminVisibility);
123→
124→    // Also check immediately in case user data is already available
125→    updateAdminVisibility();
126→
127→    // Logout button functionality
128→    const logoutButtonSidebar = document.getElementById('logoutButtonSidebar');
129→    if (logoutButtonSidebar) {
130→        logoutButtonSidebar.addEventListener('click', async () => {
131→            try {
132→                const response = await fetch('/api/auth/logout', {
133→                    method: 'POST',
134→                    headers: {
135→                        // Add any necessary headers, e.g., CSRF token if re-enabled
136→                    }
137→                });
138→                if (response.ok) {
139→                    // Clear potential client-side user state
140→                    if (window.currentUser) {
141→                        window.currentUser = null;
142→                    }
143→                    // Dispatch an event to notify other components that user logged out
144→                    window.dispatchEvent(new CustomEvent('userLoggedOut'));
145→                    // Redirect to login page
146→                    window.location.href = '/login';
147→                } else {
148→                    const errorData = await response.json().catch(() => ({ message: 'Logout failed. Please try again.' }));
149→                    console.error('Logout failed:', response.status, errorData);
150→                    alert(errorData.message || 'Logout failed. Please try again.');
151→                }
152→            } catch (error) {
153→                console.error('Logout request failed:', error);
154→                alert('An error occurred during logout.');
155→            }
156→        });
157→    }
158→</script>
