  1→import React, { useState, useEffect } from 'react';
  2→import type { FormEvent } from 'react'; // Use type-only import
  3→
  4→interface ExternalProvider {
  5→    id: number;
  6→    name: string;
  7→    type: string;
  8→    buttonText: string;
  9→    buttonColor: string;
 10→}
 11→
 12→const Login = () => {
 13→    const [username, setUsername] = useState('');
 14→    const [password, setPassword] = useState('');
 15→    const [error, setError] = useState<string | null>(null);
 16→    const [isLoading, setIsLoading] = useState(false);
 17→    const [externalProviders, setExternalProviders] = useState<ExternalProvider[]>([]);
 18→
 19→    useEffect(() => {
 20→        fetchExternalProviders();
 21→    }, []);
 22→
 23→    // Read OAuth error from URL parameter (redirected from backend on OAuth failure)
 24→    useEffect(() => {
 25→        const params = new URLSearchParams(window.location.search);
 26→        const errorParam = params.get('error');
 27→        if (errorParam) {
 28→            setError(decodeURIComponent(errorParam));
 29→            // Clean URL to prevent error persisting on refresh
 30→            window.history.replaceState({}, '', '/login');
 31→        }
 32→    }, []);
 33→
 34→    const fetchExternalProviders = async () => {
 35→        try {
 36→            console.log('[OAuth] Fetching enabled identity providers from /api/identity-providers/enabled');
 37→            const response = await fetch('/api/identity-providers/enabled');
 38→            if (response.ok) {
 39→                const data = await response.json();
 40→                console.log('[OAuth] Successfully fetched identity providers:', data);
 41→                console.log('[OAuth] Number of providers:', data.length);
 42→                setExternalProviders(data);
 43→            } else {
 44→                console.error('[OAuth] Failed to fetch providers, status:', response.status);
 45→            }
 46→        } catch (err) {
 47→            console.error('[OAuth] Failed to load external providers:', err);
 48→        }
 49→    };
 50→
 51→    const handleExternalLogin = async (providerId: number) => {
 52→        const provider = externalProviders.find(p => p.id === providerId);
 53→        console.log('=== OAuth Login Flow START ===');
 54→        console.log('[OAuth] Provider ID:', providerId);
 55→        console.log('[OAuth] Provider details:', provider);
 56→        console.log('[OAuth] Current window.location.origin:', window.location.origin);
 57→        console.log('[OAuth] Current window.location.href:', window.location.href);
 58→
 59→        // Clear any stale authentication data before starting fresh OAuth flow
 60→        // This prevents issues with cached OAuth states in corporate AAD environments
 61→        console.log('[OAuth] Clearing stale authentication data...');
 62→        localStorage.removeItem('authToken'); // Legacy cleanup
 63→        localStorage.removeItem('user');
 64→        sessionStorage.clear(); // Clear any cached OAuth-related data
 65→
 66→        // Delete legacy auth cookies to ensure fresh OAuth flow
 67→        document.cookie = 'authToken=; path=/; expires=Thu, 01 Jan 1970 00:00:00 GMT';
 68→
 69→        // Clear the HttpOnly auth cookie via backend endpoint.
 70→        // This is the primary defense against the stale-cookie login loop where an expired
 71→        // secman_auth cookie causes Micronaut to reject OAuth requests before the controller runs.
 72→        try {
 73→            console.log('[OAuth] Clearing HttpOnly auth cookie via /api/auth/clear-session...');
 74→            await fetch('/api/auth/clear-session', { method: 'POST', credentials: 'include' });
 75→            console.log('[OAuth] HttpOnly auth cookie cleared successfully');
 76→        } catch (err) {
 77→            // Non-fatal: CookieTokenReader path-skip is the primary fix
 78→            console.warn('[OAuth] Failed to clear session cookie (non-fatal):', err);
 79→        }
 80→
 81→        // Generate a fresh login nonce to ensure state uniqueness
 82→        const loginNonce = Date.now().toString(36) + Math.random().toString(36).substr(2);
 83→        sessionStorage.setItem('oauth_login_nonce', loginNonce);
 84→        console.log('[OAuth] Generated login nonce:', loginNonce);
 85→
 86→        // Add cache-busting parameter to force fresh OAuth state generation
 87→        const redirectUrl = `/oauth/authorize/${providerId}?_t=${loginNonce}`;
 88→        console.log('[OAuth] Redirecting to:', redirectUrl);
 89→        console.log('[OAuth] Full URL will be:', window.location.origin + redirectUrl);
 90→        console.log('[OAuth] Browser will now redirect to backend OAuth endpoint');
 91→        console.log('=== OAuth Login Flow - Browser Redirect ===');
 92→
 93→        window.location.href = redirectUrl;
 94→    };
 95→
 96→    const handleSubmit = async (e: FormEvent) => {
 97→        e.preventDefault();
 98→        setError(null);
 99→        setIsLoading(true);
100→
101→        try {
102→            const response = await fetch('/api/auth/login', {
103→                method: 'POST',
104→                headers: {
105→                    'Content-Type': 'application/json',
106→                },
107→                credentials: 'include',
108→                body: JSON.stringify({ username, password }),
109→            });
110→
111→            const data = await response.json();
112→
113→            if (response.ok) {
114→                // Login successful - JWT is now stored in HttpOnly cookie by backend
115→                // Store user data for UI display (non-sensitive info only)
116→                const userData = {
117→                    id: data.id,
118→                    username: data.username,
119→                    email: data.email,
120→                    roles: data.roles
121→                };
122→                localStorage.setItem('user', JSON.stringify(userData));
123→                // Note: Token is NOT stored in localStorage for security (XSS protection)
124→                // Authentication is handled via HttpOnly cookie set by backend
125→
126→                // Set global user state for Header component
127→                (window as any).currentUser = userData;
128→                window.dispatchEvent(new CustomEvent('userLoaded'));
129→
130→                // Small delay to ensure localStorage is written before redirect
131→                setTimeout(() => {
132→                    window.location.href = '/'; // Or '/dashboard' if you have a dedicated page
133→                }, 100);
134→            } else {
135→                setError(data.error || 'Login failed. Please check your credentials.');
136→            }
137→        } catch (err) {
138→            console.error('Login request failed:', err);
139→            setError('An error occurred during login. Please try again.');
140→        } finally {
141→            setIsLoading(false);
142→        }
143→    };
144→
145→    return (
146→        <div className="container mt-5">
147→            <div className="row justify-content-center">
148→                <div className="col-md-6 col-lg-4">
149→                    <div className="card">
150→                        <div className="card-body">
151→                            <div className="text-center mb-4">
152→                                <img src="/SecManLogo.png" alt="SecMan" height="90" className="mb-3" />
153→                                <h3 className="card-title">Login</h3>
154→                            </div>
155→
156→                            {/* External Identity Providers */}
157→                            {externalProviders.length > 0 && (
158→                                <div className="mb-4">
159→                                    <div className="text-center mb-3">
160→                                        <small className="text-muted">Sign in with</small>
161→                                    </div>
162→                                    <div className="d-grid gap-2">
163→                                        {externalProviders.map(provider => (
164→                                            <button
165→                                                key={provider.id}
166→                                                type="button"
167→                                                className="btn"
168→                                                style={{
169→                                                    backgroundColor: provider.buttonColor,
170→                                                    color: '#fff',
171→                                                    border: 'none'
172→                                                }}
173→                                                onClick={() => handleExternalLogin(provider.id)}
174→                                                disabled={isLoading}
175→                                            >
176→                                                <i className="bi bi-box-arrow-in-right me-2"></i>
177→                                                {provider.buttonText}
178→                                            </button>
179→                                        ))}
180→                                    </div>
181→                                    <div className="text-center my-3">
182→                                        <small className="text-muted">or</small>
183→                                    </div>
184→                                </div>
185→                            )}
186→
187→                            <form onSubmit={handleSubmit}>
188→                                <div className="mb-3">
189→                                    <label htmlFor="username" className="form-label">Username</label>
190→                                    <input
191→                                        type="text"
192→                                        className="form-control"
193→                                        id="username"
194→                                        value={username}
195→                                        onChange={(e) => setUsername(e.target.value)}
196→                                        required
197→                                        disabled={isLoading}
198→                                    />
199→                                </div>
200→                                <div className="mb-3">
201→                                    <label htmlFor="password" className="form-label">Password</label>
202→                                    <input
203→                                        type="password"
204→                                        className="form-control"
205→                                        id="password"
206→                                        value={password}
207→                                        onChange={(e) => setPassword(e.target.value)}
208→                                        required
209→                                        disabled={isLoading}
210→                                    />
211→                                </div>
212→                                {error && (
213→                                    <div className="alert alert-danger" role="alert">
214→                                        <strong>Login failed:</strong> {error}
215→                                        <div className="mt-2">
216→                                            <small className="text-muted">
217→                                                If this persists, try clearing your browser cache or contact IT support.
218→                                            </small>
219→                                        </div>
220→                                    </div>
221→                                )}
222→                                <div className="d-grid">
223→                                    <button type="submit" className="btn btn-primary" disabled={isLoading}>
224→                                        {isLoading ? 'Logging in...' : 'Login'}
225→                                    </button>
226→                                </div>
227→                            </form>
228→                        </div>
229→                    </div>
230→                </div>
231→            </div>
232→        </div>
233→    );
234→};
235→
236→export default Login;
237→

