 1→import React, { useState, useEffect } from 'react';
 2→
 3→// Define an interface for the user data expected from the backend
 4→interface User {
 5→    id: number;
 6→    username: string;
 7→    email: string;
 8→    roles: string[];
 9→}
10→
11→// Define a type for the global variable
12→declare global {
13→    interface Window {
14→        currentUser?: User | null;
15→    }
16→}
17→
18→const TopBar = () => {
19→    const [user, setUser] = useState<User | null>(null);
20→    const [isLoading, setIsLoading] = useState(true); // Start as loading
21→
22→    useEffect(() => {
23→        let isMounted = true; // Track mount status
24→
25→        const updateUserStatus = () => {
26→            console.log("TopBar: Updating user status. Current window.currentUser:", window.currentUser);
27→            if (isMounted) {
28→                setUser(window.currentUser || null);
29→                setIsLoading(false); // Finished loading/checking
30→            }
31→        };
32→
33→        // Check immediately if user data is already available
34→        if (window.currentUser !== undefined) {
35→             console.log("TopBar: Initial check, currentUser exists:", window.currentUser);
36→             updateUserStatus();
37→        } else {
38→             console.log("TopBar: Initial check, currentUser undefined, waiting for event.");
39→             // Set loading true explicitly if we need to wait
40→             setIsLoading(true);
41→        }
42→
43→
44→        // Listen for the custom event dispatched when user data is loaded/updated
45→        window.addEventListener('userLoaded', updateUserStatus);
46→        console.log("TopBar: Added userLoaded listener.");
47→
48→        // Also listen for logout event if we implement one, or re-check on visibility change
49→        // For simplicity, we rely on page reload after logout for now.
50→
51→        // Cleanup listener on component unmount
52→        return () => {
53→            isMounted = false;
54→            window.removeEventListener('userLoaded', updateUserStatus);
55→            console.log("TopBar: Removed userLoaded listener.");
56→        };
57→    }, []); // Empty dependency array ensures this runs once on mount and cleans up on unmount
58→
59→    return (
60→        <div className="ms-auto d-flex align-items-center"> {/* Use ms-auto to push to the right */}
61→            {isLoading ? (
62→                <span className="navbar-text me-3">Loading...</span>
63→            ) : user ? (
64→                <span className="navbar-text me-3">
65→                    Welcome, <i className="bi bi-person-fill me-1"></i>
66→                    <strong>{user.username}</strong>
