 18→
 19→    useEffect(() => {
 20→        fetchExternalProviders();
 21→    }, []);
 22→
 23→    // Read OAuth error from URL parameter (redirected from backend on OAuth failure)
 24→    useEffect(() => {
 25→        const params = new URLSearchParams(window.location.search);
 26→        const errorParam = params.get('error');
 27→        if (errorParam) {
 28→            setError(decodeURIComponent(errorParam));
 29→            // Clean URL to prevent error persisting on refresh
 30→            window.history.replaceState({}, '', '/login');
 31→        }
 32→    }, []);
 33→
 34→    const fetchExternalProviders = async () => {
 35→        try {
 36→            console.log('[OAuth] Fetching enabled identity providers from /api/identity-providers/enabled');
 37→            const response = await fetch('/api/identity-providers/enabled');
 38→            if (response.ok) {
 39→                const data = await response.json();
 40→                console.log('[OAuth] Successfully fetched identity providers:', data);
 41→                console.log('[OAuth] Number of providers:', data.length);
 42→                setExternalProviders(data);
 43→            } else {
 44→                console.error('[OAuth] Failed to fetch providers, status:', response.status);
 45→            }
 46→        } catch (err) {
 47→            console.error('[OAuth] Failed to load external providers:', err);
 48→        }
 49→    };
 50→
 51→    const handleExternalLogin = async (providerId: number) => {
 52→        const provider = externalProviders.find(p => p.id === providerId);
 53→        console.log('=== OAuth Login Flow START ===');
 54→        console.log('[OAuth] Provider ID:', providerId);
 55→        console.log('[OAuth] Provider details:', provider);
 56→        console.log('[OAuth] Current window.location.origin:', window.location.origin);
 57→        console.log('[OAuth] Current window.location.href:', window.location.href);
 58→
 59→        // Clear any stale authentication data before starting fresh OAuth flow
 60→        // This prevents issues with cached OAuth states in corporate AAD environments
 61→        console.log('[OAuth] Clearing stale authentication data...');
 62→        localStorage.removeItem('authToken'); // Legacy cleanup
 63→        localStorage.removeItem('user');
 64→        sessionStorage.clear(); // Clear any cached OAuth-related data
 65→
 66→        // Delete legacy auth cookies to ensure fresh OAuth flow
 67→        document.cookie = 'authToken=; path=/; expires=Thu, 01 Jan 1970 00:00:00 GMT';
 68→
 69→        // Clear the HttpOnly auth cookie via backend endpoint.
 70→        // This is the primary defense against the stale-cookie login loop where an expired
 71→        // secman_auth cookie causes Micronaut to reject OAuth requests before the controller runs.
 72→        try {
 73→            console.log('[OAuth] Clearing HttpOnly auth cookie via /api/auth/clear-session...');
 74→            await fetch('/api/auth/clear-session', { method: 'POST', credentials: 'include' });
 75→            console.log('[OAuth] HttpOnly auth cookie cleared successfully');
 76→        } catch (err) {
 77→            // Non-fatal: CookieTokenReader path-skip is the primary fix
 78→            console.warn('[OAuth] Failed to clear session cookie (non-fatal):', err);
 79→        }
 80→
 81→        // Generate a fresh login nonce to ensure state uniqueness
 82→        const loginNonce = Date.now().toString(36) + Math.random().toString(36).substr(2);
 83→        sessionStorage.setItem('oauth_login_nonce', loginNonce);
 84→        console.log('[OAuth] Generated login nonce:', loginNonce);
 85→
 86→        // Add cache-busting parameter to force fresh OAuth state generation
 87→        const redirectUrl = `/oauth/authorize/${providerId}?_t=${loginNonce}`;
 88→        console.log('[OAuth] Redirecting to:', redirectUrl);
 89→        console.log('[OAuth] Full URL will be:', window.location.origin + redirectUrl);
 90→        console.log('[OAuth] Browser will now redirect to backend OAuth endpoint');
 91→        console.log('=== OAuth Login Flow - Browser Redirect ===');
 92→
 93→        window.location.href = redirectUrl;
 94→    };
