  2→ * React wrapper component for Vulnerability Statistics page
  3→ *
  4→ * Manages domain filter state and passes it to all statistics components.
  5→ * This component is used as the main React island in the Astro page.
  6→ *
  7→ * Feature: 059-vuln-stats-domain-filter
  8→ * Task: T015, T016 [US1]
  9→ * Spec reference: spec.md FR-004 (update all components when domain selected)
 10→ * User Story: US1 - Filter Statistics by Domain (P1)
 11→ */
 12→
 13→import React, { useState, useEffect } from 'react';
 14→import AwsHostedToggle from './AwsHostedToggle';
 15→import DomainSelector from './DomainSelector';
 16→import MostCommonVulnerabilities from './MostCommonVulnerabilities';
 17→import MostVulnerableProducts from './MostVulnerableProducts';
 18→import SeverityDistributionChart from './SeverityDistributionChart';
 19→import TopAssetsByVulnerabilities from './TopAssetsByVulnerabilities';
 20→
 21→/** Session storage key for domain persistence (per spec) */
 22→const STORAGE_KEY = 'secman.vuln-stats.selectedDomain';
 23→/** Session storage key for AWS hosted toggle persistence */
 24→const AWS_HOSTED_STORAGE_KEY = 'secman.vuln-stats.awsHosted';
 25→
 26→export default function VulnerabilityStatisticsPage() {
 27→  // Domain filter state - lifted to page level for all components
 28→  const [selectedDomain, setSelectedDomain] = useState<string | null>(() => {
 29→    // Initialize from sessionStorage (US2: Persist Domain Selection)
 30→    if (typeof window !== 'undefined') {
 31→      return sessionStorage.getItem(STORAGE_KEY);
 32→    }
 33→    return null;
 34→  });
 35→
 36→  // AWS Hosted filter state - lifted to page level for all components
 37→  const [awsHosted, setAwsHosted] = useState<boolean>(() => {
 38→    if (typeof window !== 'undefined') {
 39→      return sessionStorage.getItem(AWS_HOSTED_STORAGE_KEY) === 'true';
 40→    }
 41→    return false;
 42→  });
 43→
 44→  // Handle domain change
 45→  const handleDomainChange = (domain: string | null) => {
 46→    setSelectedDomain(domain);
 47→  };
 48→
 49→  // Handle AWS Hosted toggle change
 50→  const handleAwsHostedToggle = (enabled: boolean) => {
 51→    setAwsHosted(enabled);
 52→    if (enabled) {
 53→      sessionStorage.setItem(AWS_HOSTED_STORAGE_KEY, 'true');
 54→    } else {
 55→      sessionStorage.removeItem(AWS_HOSTED_STORAGE_KEY);
 56→    }
 57→  };
 58→
 59→  return (
 60→    <>
 61→      {/* Page Header with Domain Selector */}
 62→      <div className="row mb-4">
 63→        <div className="col-12">
 64→          <div className="d-flex flex-column flex-md-row justify-content-between align-items-start align-items-md-center gap-3">
 65→            <div>
 66→              <h1 className="display-5 mb-1">
 67→                <i className="bi bi-bar-chart-line me-2"></i>
 68→                Vulnerability Statistics Lense
 69→              </h1>
 70→              <p className="text-muted mb-0">
 71→                Comprehensive vulnerability analytics and trends across your accessible assets
 72→              </p>
 73→            </div>
 74→            {/* Filters in header for prominent placement (FR-001) */}
 75→            <div className="d-flex align-items-center gap-3 flex-nowrap">
 76→              <AwsHostedToggle
 77→                awsHosted={awsHosted}
 78→                onToggle={handleAwsHostedToggle}
 79→              />
 80→              <DomainSelector
 81→                selectedDomain={selectedDomain}
 82→                onDomainChange={handleDomainChange}
 83→              />
 84→            </div>
 85→          </div>
 86→        </div>
 87→      </div>
 88→
 89→      {/* User Story 1: Most Common Vulnerabilities (P1/MVP) */}
 90→      <div className="row mb-4">
 91→        <div className="col-12">
 92→          <MostCommonVulnerabilities domain={selectedDomain} awsHosted={awsHosted} />
 93→        </div>
 94→      </div>
 95→
 96→      {/* Most Vulnerable Products */}
 97→      <div className="row mb-4">
 98→        <div className="col-12">
 99→          <MostVulnerableProducts domain={selectedDomain} awsHosted={awsHosted} />
100→        </div>
101→      </div>
102→
103→      {/* User Story 2: Severity Distribution (P2) */}
104→      <div className="row mb-4">
105→        <div className="col-12">
106→          <SeverityDistributionChart domain={selectedDomain} awsHosted={awsHosted} />
107→        </div>
108→      </div>
109→
110→      {/* User Story 3: Top Assets by Vulnerability Count (P3) */}
111→      <div className="row mb-4">
112→        <div className="col-12">
113→          <TopAssetsByVulnerabilities domain={selectedDomain} awsHosted={awsHosted} />
114→        </div>
115→      </div>
116→    </>
117→  );
118→}
