  1→/**
  2→ * Exception Badge Service - Real-time SSE updates for pending exception count
  3→ *
  4→ * Provides Server-Sent Events (SSE) connection to receive real-time updates
  5→ * of pending exception request counts for badge display in the sidebar.
  6→ *
  7→ * **Features**:
  8→ * - Automatic SSE connection management
  9→ * - Callback-based updates (observer pattern)
 10→ * - Error handling and auto-reconnection
 11→ * - Connection state tracking
 12→ *
 13→ * **Usage**:
 14→ * ```typescript
 15→ * const disconnect = connectToBadgeUpdates((count) => {
 16→ *   setBadgeCount(count);
 17→ * });
 18→ *
 19→ * // Later, cleanup:
 20→ * disconnect();
 21→ * ```
 22→ *
 23→ * Feature: 031-vuln-exception-approval
 24→ * User Story 3: ADMIN Approval Dashboard (P1)
 25→ * Phase 6: Real-Time Badge Updates
 26→ * Reference: spec.md FR-024
 27→ */
 28→
 29→/**
 30→ * Callback function type for badge count updates.
 31→ *
 32→ * @param count The new pending exception count
 33→ */
 34→export type BadgeCountCallback = (count: number) => void;
 35→
 36→// Track connection state to prevent reconnection storms
 37→let connectionState: 'disconnected' | 'connecting' | 'connected' | 'error' = 'disconnected';
 38→let errorCount = 0;
 39→const MAX_ERRORS = 5;
 40→const STABLE_CONNECTION_THRESHOLD = 10000; // Must be connected for 10s before resetting error count
 41→let reconnectTimeoutId: ReturnType<typeof setTimeout> | null = null;
 42→let errorResetTimeoutId: ReturnType<typeof setTimeout> | null = null;
 43→let connectionStartTime: number = 0;
 44→
 45→/**
 46→ * Connect to SSE endpoint for real-time badge count updates.
 47→ *
 48→ * **Event Flow**:
 49→ * 1. Establishes EventSource connection to /api/exception-badge-updates
 50→ * 2. Receives initial count event immediately
 51→ * 3. Receives subsequent count updates when pending count changes
 52→ * 4. Calls onUpdate callback with new count
 53→ *
 54→ * **Event Format** (from backend):
 55→ * ```
 56→ * event: count-update
 57→ * data: {"pendingCount": 5}
 58→ * ```
 59→ *
 60→ * **Error Handling**:
 61→ * - Logs connection errors to console
 62→ * - Prevents reconnection storms by tracking error count
 63→ * - After 5 consecutive errors, stops reconnection attempts
 64→ * - Callback receives 0 on connection errors (safe fallback)
 65→ *
 66→ * **Authentication**:
 67→ * - Uses HttpOnly cookie-based authentication (withCredentials: true)
 68→ * - Browser automatically sends the secman_auth cookie with the request
 69→ * - Requires authenticated session (401 if not logged in)
 70→ *
 71→ * @param onUpdate Callback function to receive count updates
 72→ * @returns Cleanup function to disconnect SSE connection
 73→ *
 74→ * @example
 75→ * ```typescript
 76→ * // In React component:
 77→ * useEffect(() => {
 78→ *   const disconnect = connectToBadgeUpdates((count) => {
 79→ *     setPendingCount(count);
 80→ *   });
 81→ *
 82→ *   return () => disconnect(); // Cleanup on unmount
 83→ * }, []);
 84→ * ```
 85→ */
 86→export function connectToBadgeUpdates(onUpdate: BadgeCountCallback): () => void {
 87→  // Prevent multiple simultaneous connection attempts
 88→  if (connectionState === 'connecting' || connectionState === 'connected') {
 89→    console.warn('[ExceptionBadge] Connection already in progress or established');
 90→    return () => {}; // No-op cleanup
 91→  }
 92→
 93→  // Stop reconnection attempts after too many errors
 94→  if (errorCount >= MAX_ERRORS) {
 95→    console.error('[ExceptionBadge] Too many connection errors, stopping reconnection attempts. Please refresh the page to retry.');
 96→    onUpdate(0);
 97→    return () => {};
 98→  }
 99→
100→  connectionState = 'connecting';
101→  console.log('[ExceptionBadge] Connecting to SSE endpoint for real-time updates');
102→
103→  // Create EventSource connection with credentials to send HttpOnly auth cookie
104→  // The backend CookieTokenReader will extract the JWT from the secman_auth cookie
105→  const eventSource = new EventSource('/api/exception-badge-updates', { withCredentials: true });
106→
107→  let isCleaningUp = false;
108→
109→  // Handle count-update events
110→  eventSource.addEventListener('count-update', (event: MessageEvent) => {
111→    try {
112→      const data = JSON.parse(event.data);
113→      const newCount = data.pendingCount;
114→
115→      console.log('[ExceptionBadge] Received count update:', newCount);
116→      onUpdate(newCount);
117→
118→      // Schedule error count reset only after stable connection (10 seconds)
119→      // This prevents infinite retry loops when server closes connection after each message
120→      if (errorCount > 0 && !errorResetTimeoutId) {
121→        errorResetTimeoutId = setTimeout(() => {
122→          if (connectionState === 'connected') {
123→            console.log('[ExceptionBadge] Connection stable, resetting error count');
124→            errorCount = 0;
125→          }
126→          errorResetTimeoutId = null;
127→        }, STABLE_CONNECTION_THRESHOLD);
128→      }
129→    } catch (error) {
130→      console.error('[ExceptionBadge] Failed to parse count update event:', error, event.data);
131→    }
132→  });
133→
134→  // Handle connection opened
135→  eventSource.addEventListener('open', () => {
136→    console.log('[ExceptionBadge] SSE connection established');
137→    connectionState = 'connected';
138→    connectionStartTime = Date.now();
139→    // NOTE: errorCount is only reset after stable connection (10s of successful operation)
140→    // This prevents infinite retry loops when connection immediately errors after receiving data
141→  });
142→
143→  // Handle connection errors
144→  eventSource.addEventListener('error', (error) => {
145→    if (isCleaningUp) {
146→      return; // Ignore errors during cleanup
147→    }
148→
149→    // Cancel any pending error count reset since we're not stable
150→    if (errorResetTimeoutId) {
151→      clearTimeout(errorResetTimeoutId);
152→      errorResetTimeoutId = null;
153→    }
154→
155→    errorCount++;
156→    connectionState = 'error';
157→
158→    console.error(`[ExceptionBadge] SSE connection error (${errorCount}/${MAX_ERRORS}):`, error);
159→
160→    // ALWAYS close EventSource to prevent browser auto-reconnect
161→    eventSource.close();
162→
163→    // Fallback to 0 count on error (safe default)
164→    onUpdate(0);
165→
166→    // Stop if max errors reached
167→    if (errorCount >= MAX_ERRORS) {
168→      console.error('[ExceptionBadge] Maximum errors reached, stopping reconnection. Refresh page to retry.');
169→      connectionState = 'disconnected';
170→      return;
171→    }
172→
173→    // Exponential backoff: 1s, 2s, 4s, 8s, 16s (capped at 30s)
174→    const backoffDelay = Math.min(1000 * Math.pow(2, errorCount - 1), 30000);
175→    console.log(`[ExceptionBadge] Will retry in ${backoffDelay / 1000}s...`);
176→
177→    connectionState = 'disconnected';
178→
179→    // Schedule reconnection with backoff
180→    reconnectTimeoutId = setTimeout(() => {
181→      reconnectTimeoutId = null;
182→      connectToBadgeUpdates(onUpdate);
183→    }, backoffDelay);
184→  });
185→
186→  // Return cleanup function
187→  return () => {
188→    isCleaningUp = true;
189→    console.log('[ExceptionBadge] Disconnecting from SSE endpoint');
190→    eventSource.close();
191→    connectionState = 'disconnected';
192→    // Cancel any pending reconnection attempt
193→    if (reconnectTimeoutId) {
194→      clearTimeout(reconnectTimeoutId);
195→      reconnectTimeoutId = null;
196→    }
197→    // Cancel any pending error count reset
198→    if (errorResetTimeoutId) {
199→      clearTimeout(errorResetTimeoutId);
200→      errorResetTimeoutId = null;
201→    }
202→  };
203→}
204→
205→/**
206→ * Fetch current pending count via HTTP (fallback for SSE failures).
207→ *
208→ * Used as a backup method when SSE is not available or fails.
209→ * Polls the backend for the current count.
210→ *
211→ * **Use Case**: Browsers without EventSource support, or when SSE fails repeatedly
212→ *
213→ * @returns Promise resolving to current pending count
214→ * @throws Error if request fails or user not authenticated
215→ *
216→ * @example
217→ * ```typescript
218→ * try {
219→ *   const count = await fetchPendingCount();
220→ *   setBadgeCount(count);
221→ * } catch (error) {
222→ *   console.error('Failed to fetch count:', error);
223→ *   setBadgeCount(0);
224→ * }
225→ * ```
226→ */
227→export async function fetchPendingCount(): Promise<number> {
228→  const response = await fetch('/api/vulnerability-exception-requests/pending/count', {
229→    method: 'GET',
230→    credentials: 'include', // Include session cookies
231→    headers: {
232→      'Accept': 'application/json'
233→    }
234→  });
235→
236→  if (!response.ok) {
237→    if (response.status === 401) {
238→      throw new Error('Unauthorized: User not authenticated');
239→    }
240→    throw new Error(`Failed to fetch pending count: ${response.status} ${response.statusText}`);
241→  }
242→
243→  const data = await response.json();
244→  return data.count || 0;
245→}
