 80→ *   });
 81→ *
 82→ *   return () => disconnect(); // Cleanup on unmount
 83→ * }, []);
 84→ * ```
 85→ */
 86→export function connectToBadgeUpdates(onUpdate: BadgeCountCallback): () => void {
 87→  // Prevent multiple simultaneous connection attempts
 88→  if (connectionState === 'connecting' || connectionState === 'connected') {
 89→    console.warn('[ExceptionBadge] Connection already in progress or established');
 90→    return () => {}; // No-op cleanup
 91→  }
 92→
 93→  // Stop reconnection attempts after too many errors
 94→  if (errorCount >= MAX_ERRORS) {
 95→    console.error('[ExceptionBadge] Too many connection errors, stopping reconnection attempts. Please refresh the page to retry.');
 96→    onUpdate(0);
 97→    return () => {};
 98→  }
 99→
100→  connectionState = 'connecting';
101→  console.log('[ExceptionBadge] Connecting to SSE endpoint for real-time updates');
102→
103→  // Create EventSource connection with credentials to send HttpOnly auth cookie
104→  // The backend CookieTokenReader will extract the JWT from the secman_auth cookie
105→  const eventSource = new EventSource('/api/exception-badge-updates', { withCredentials: true });
106→
107→  let isCleaningUp = false;
108→
109→  // Handle count-update events
110→  eventSource.addEventListener('count-update', (event: MessageEvent) => {
111→    try {
112→      const data = JSON.parse(event.data);
113→      const newCount = data.pendingCount;
