118→      // Schedule error count reset only after stable connection (10 seconds)
119→      // This prevents infinite retry loops when server closes connection after each message
120→      if (errorCount > 0 && !errorResetTimeoutId) {
121→        errorResetTimeoutId = setTimeout(() => {
122→          if (connectionState === 'connected') {
123→            console.log('[ExceptionBadge] Connection stable, resetting error count');
124→            errorCount = 0;
125→          }
126→          errorResetTimeoutId = null;
127→        }, STABLE_CONNECTION_THRESHOLD);
128→      }
129→    } catch (error) {
