131→    }
132→  });
133→
134→  // Handle connection opened
135→  eventSource.addEventListener('open', () => {
136→    console.log('[ExceptionBadge] SSE connection established');
137→    connectionState = 'connected';
138→    connectionStartTime = Date.now();
139→    // NOTE: errorCount is only reset after stable connection (10s of successful operation)
140→    // This prevents infinite retry loops when connection immediately errors after receiving data
141→  });
142→
143→  // Handle connection errors
144→  eventSource.addEventListener('error', (error) => {
145→    if (isCleaningUp) {
146→      return; // Ignore errors during cleanup
147→    }
148→
149→    // Cancel any pending error count reset since we're not stable
150→    if (errorResetTimeoutId) {
151→      clearTimeout(errorResetTimeoutId);
152→      errorResetTimeoutId = null;
153→    }
154→
155→    errorCount++;
156→    connectionState = 'error';
157→
158→    console.error(`[ExceptionBadge] SSE connection error (${errorCount}/${MAX_ERRORS}):`, error);
159→
160→    // ALWAYS close EventSource to prevent browser auto-reconnect
161→    eventSource.close();
162→
163→    // Fallback to 0 count on error (safe default)
164→    onUpdate(0);
165→
166→    // Stop if max errors reached
167→    if (errorCount >= MAX_ERRORS) {
168→      console.error('[ExceptionBadge] Maximum errors reached, stopping reconnection. Refresh page to retry.');
169→      connectionState = 'disconnected';
170→      return;
171→    }
172→
173→    // Exponential backoff: 1s, 2s, 4s, 8s, 16s (capped at 30s)
174→    const backoffDelay = Math.min(1000 * Math.pow(2, errorCount - 1), 30000);
175→    console.log(`[ExceptionBadge] Will retry in ${backoffDelay / 1000}s...`);
176→
177→    connectionState = 'disconnected';
178→
179→    // Schedule reconnection with backoff
180→    reconnectTimeoutId = setTimeout(() => {
181→      reconnectTimeoutId = null;
