187→  return () => {
188→    isCleaningUp = true;
189→    console.log('[ExceptionBadge] Disconnecting from SSE endpoint');
190→    eventSource.close();
191→    connectionState = 'disconnected';
192→    // Cancel any pending reconnection attempt
193→    if (reconnectTimeoutId) {
194→      clearTimeout(reconnectTimeoutId);
195→      reconnectTimeoutId = null;
196→    }
197→    // Cancel any pending error count reset
198→    if (errorResetTimeoutId) {
